// ========================================
// CLIENT CONFIGURATION - CHANGE THIS!
// ========================================
const CLIENT_ID = 'YOUR_CLIENT_ID';  // <-- CHANGE THIS FOR EACH CLIENT
// ========================================

const data = $input.item.json;

return {
  json: {
    client_id: CLIENT_ID,
    sessionId: data.sessionId || data.body?.sessionId || `session_${Date.now()}`,
    chatInput: data.chatInput || data.body?.chatInput || '',
    action: data.action || data.body?.action || 'sendMessage',
    name: data.body?.name || data.name || '',
    email: data.body?.email || data.email || '',
    phone: data.body?.phone || data.phone || '',
    originalData: data
  }
};

// ============================================
// PREPARE CLIENT CONTEXT WITH CACHING
// Cache TTL: 1 hour (3600000ms)
// ============================================

const clientData = $('Load Client Variables').first().json;
const sessionData = $('Extract Client Config').first().json;
const vars = clientData.variables || {};
const clientId = clientData.client_id;

// Get workflow static data for caching
const staticData = $getWorkflowStaticData('global');
const cacheKey = `client_${clientId}`;
const cacheTimeKey = `${cacheKey}_time`;
const CACHE_TTL = 3600000; // 1 hour in milliseconds

// Check if we have valid cached maps
let LOCATION_MAP = {};
let TYPE_MAP = {};
let FEATURE_MAP = {};

const now = Date.now();
const cachedTime = staticData[cacheTimeKey] || 0;
const cacheAge = now - cachedTime;

if (staticData[cacheKey] && cacheAge < CACHE_TTL) {
  // Use cached data
  const cached = staticData[cacheKey];
  LOCATION_MAP = cached.LOCATION_MAP || {};
  TYPE_MAP = cached.TYPE_MAP || {};
  FEATURE_MAP = cached.FEATURE_MAP || {};
} else {
  // Parse fresh data from DB and cache it
  LOCATION_MAP = typeof vars.LOCATION_MAP === 'string' ? JSON.parse(vars.LOCATION_MAP || '{}') : (vars.LOCATION_MAP || {});
  TYPE_MAP = typeof vars.TYPE_MAP === 'string' ? JSON.parse(vars.TYPE_MAP || '{}') : (vars.TYPE_MAP || {});
  FEATURE_MAP = typeof vars.FEATURE_MAP === 'string' ? JSON.parse(vars.FEATURE_MAP || '{}') : (vars.FEATURE_MAP || {});

  // Store in cache
  staticData[cacheKey] = {
    LOCATION_MAP,
    TYPE_MAP,
    FEATURE_MAP
  };
  staticData[cacheTimeKey] = now;
}

return {
  json: {
    CLIENT_ID: clientId,
    PROP_API_BASE_URL: clientData.api_base_url || vars.PROP_API_BASE_URL || '',
    PROP_AUTH_HEADER: clientData.api_token || vars.PROP_AUTH_HEADER,
    RAG_WEBSITE: vars.RAG_WEBSITE || '',
    BOT_NAME: vars.BOT_NAME || 'Property Assistant',
    OWNER_EMAIL: vars.OWNER_EMAIL || '',
    PROP_DETAIL_URL: vars.PROP_DETAIL_URL || '',
    LOCATION_MAP: LOCATION_MAP,
    TYPE_MAP: TYPE_MAP,
    FEATURE_MAP: FEATURE_MAP,
    sessionId: sessionData.sessionId,
    chatInput: sessionData.chatInput,
    action: sessionData.action,
    name: sessionData.name || '',
    email: sessionData.email || '',
    phone: sessionData.phone || '',
    _cache_info: {
      from_cache: cacheAge < CACHE_TTL && staticData[cacheKey] !== undefined,
      cache_age_seconds: Math.round(cacheAge / 1000)
    }
  }
};

// ============================================
// SMART PROPERTY SEARCH WITH NLP
// Supports: location+type, ref_no, reset, partial searches
// ============================================

const context = $json || $input.first().json || {};
const LOCATION_MAP = context.LOCATION_MAP || {};
const TYPE_MAP = context.TYPE_MAP || {};
const CLIENT_ID = context.CLIENT_ID || '';
const PROP_DETAIL_URL = context.PROP_DETAIL_URL || '';
const sessionId = context.sessionId || '';
const chatInput = (context.chatInput || '').toLowerCase();

// ============================================
// HELPER FUNCTIONS
// ============================================

// Find location in chatInput (returns single best match)
function findLocation(query, locationMap) {
  const q = query.toLowerCase();
  let bestMatch = null;
  let bestId = null;
  let bestLen = 0;

  for (const [name, id] of Object.entries(locationMap)) {
    const nameLower = name.toLowerCase();
    if (q.includes(nameLower)) {
      if (nameLower.length > bestLen) {
        bestLen = nameLower.length;
        bestMatch = name;
        bestId = id;
      }
    }
  }

  return bestMatch ? { match: bestMatch, id: bestId } : null;
}

// Find property type - prioritize LONGEST match (most specific)
// e.g., "ground floor apartment" matches "Ground Floor Apartment" not just "Apartment"
function findPropertyType(query, typeMap) {
  let q = query.toLowerCase();

  // Keyword aliases: map common user terms to API type names
  // This runs BEFORE matching so "villa" becomes "detached villa" for matching
  const keywordAliases = {
    'villa': 'detached villa',
    'villas': 'detached villa',
    'flat': 'apartment',
    'flats': 'apartment'
  };

  // Apply aliases - replace standalone keywords with their API equivalents
  for (const [keyword, replacement] of Object.entries(keywordAliases)) {
    // Use word boundary regex to match standalone words only
    const regex = new RegExp(`\\b${keyword}\\b`, 'gi');
    if (regex.test(q) && !q.includes(replacement)) {
      q = q.replace(regex, replacement);
    }
  }

  let bestMatch = null;
  let bestId = null;
  let bestLen = 0;

  // Find the LONGEST matching type (most specific)
  for (const [typeName, typeId] of Object.entries(typeMap)) {
    const nameLower = typeName.toLowerCase();
    if (q.includes(nameLower)) {
      // Prefer longer matches (more specific)
      if (nameLower.length > bestLen) {
        bestLen = nameLower.length;
        bestMatch = typeName;
        bestId = typeId;
      }
    }
  }

  return bestMatch ? { match: bestMatch, id: bestId } : null;
}

// Parse price from natural language
function parsePrice(query) {
  const q = query.toLowerCase();
  let price_min = null, price_max = null;

  const normalizeNumber = (num, suffix) => {
    let value = parseFloat(num.replace(/,/g, ''));
    if (suffix) {
      if (suffix.toLowerCase() === 'k') value *= 1000;
      if (suffix.toLowerCase() === 'm') value *= 1000000;
    }
    return value;
  };

  const between = q.match(/between\s*[\u20ac$]?\s*([\d,.]+)\s*([km])?\s*(?:and|to|-)\s*[\u20ac$]?\s*([\d,.]+)\s*([km])?/i);
  if (between) {
    price_min = normalizeNumber(between[1], between[2]);
    price_max = normalizeNumber(between[3], between[4]);
    return { price_min, price_max };
  }

  const maxMatch = q.match(/(?:under|below|max|maximum|budget|up\s*to|less\s*than)\s*[\u20ac$]?\s*([\d,.]+)\s*([km])?/i);
  if (maxMatch) {
    price_max = normalizeNumber(maxMatch[1], maxMatch[2]);
    return { price_min, price_max };
  }

  const minMatch = q.match(/(?:above|over|min|minimum|from|starting|at\s*least|more\s*than)\s*[\u20ac$]?\s*([\d,.]+)\s*([km])?/i);
  if (minMatch) {
    price_min = normalizeNumber(minMatch[1], minMatch[2]);
    return { price_min, price_max };
  }

  return { price_min, price_max };
}

// Parse bedrooms from query - returns { min, max }
// "3 bed" = 3+ bedrooms (min=3, max=0)
// "exactly 3 bed" = exactly 3 (min=3, max=3)
function parseBedrooms(query) {
  const exactMatch = query.match(/exactly\s+(\d+)\s*(?:bed|bedroom|bedrooms|br)/i);
  if (exactMatch) {
    const num = parseInt(exactMatch[1]);
    return { min: num, max: num };
  }
  const bedroomMatch = query.match(/(\d+)\s*[-]?\s*(?:bed|bedroom|bedrooms|br)/i);
  if (bedroomMatch) {
    return { min: parseInt(bedroomMatch[1]), max: 0 };
  }
  return { min: 0, max: 0 };
}

// Parse bathrooms from query - returns { min, max }
function parseBathrooms(query) {
  const exactMatch = query.match(/exactly\s+(\d+)\s*(?:bath|bathroom|bathrooms)/i);
  if (exactMatch) {
    const num = parseInt(exactMatch[1]);
    return { min: num, max: num };
  }
  const bathMatch = query.match(/(\d+)\s*[-]?\s*(?:bath|bathroom|bathrooms)/i);
  if (bathMatch) {
    return { min: parseInt(bathMatch[1]), max: 0 };
  }
  return { min: 0, max: 0 };
}

// Parse reference number
function parseRefNo(query) {
  // 1. Always match explicit "ref" prefix patterns (e.g., "ref 1234567", "reference: 1234567")
  const explicitRef = query.match(/ref(?:erence)?[\s:#]*([A-Z]?\d{4,10})/i);
  if (explicitRef) {
    let refNo = explicitRef[1].toUpperCase();
    if (/^\d+$/.test(refNo)) refNo = 'R' + refNo;
    return refNo;
  }

  // 2. Always match R-prefixed numbers (e.g., "R5272630")
  const rPrefixed = query.match(/\b(R\d{5,10})\b/i);
  if (rPrefixed) {
    return rPrefixed[1].toUpperCase();
  }

  // 3. For bare numbers (no ref/R prefix), only match if NO price keywords present
  const priceKeywords = /(?:under|below|max|maximum|budget|up\s*to|upto|less\s*than|above|over|min|minimum|from|starting|at\s*least|more\s*than|between|price|cost|\u20ac|\$|\u00a3)/i;
  if (!priceKeywords.test(query)) {
    const bareNumber = query.match(/\b(\d{5,10})\b/);
    if (bareNumber) {
      return 'R' + bareNumber[1];
    }
  }

  return null;
}

// Find multiple locations - handles "and"/"or" queries properly
// Returns array of unique locations found in the query
function findMultipleLocations(query, locationMap) {
  const locations = [];
  const q = query.toLowerCase();
  const seenIds = new Set();

  // Check each location in the map
  for (const [name, id] of Object.entries(locationMap)) {
    const nameLower = name.toLowerCase();
    // Check if this location appears in the query
    if (q.includes(nameLower) && !seenIds.has(id)) {
      seenIds.add(id);
      locations.push({ name, id });
    }
  }

  return locations;
}

// ============================================
// MAIN LOGIC
// ============================================

// Check for help command
const helpPatterns = /^(help|commands|tips|how to|what can you do|features)$/i;
if (helpPatterns.test(chatInput.trim())) {
  return '📋 **Available Commands:**\n\n' +
    '🔍 **Search:** "villas in marbella", "3 bed apartments estepona"\n' +
    '💰 **Price:** "under 500k", "budget 1m", "between 300k and 600k"\n' +
    '🛏️ **Bedrooms:** "3 bed", "4 bedroom"\n' +
    '🔑 **Reference:** "R5272630" or just "5272630"\n' +
    '🔄 **Reset:** "reset" - clears all filters\n' +
    '\n💡 **Tips:**\n' +
    '• Filters stack - add "under 500k" to narrow results\n' +
    '• Say "reset" to start fresh anytime\n' +
    '• Ask for "more" to see additional properties';
}

// Check for reset command
const resetPatterns = /^(reset|clear|start over|clear filters|new search|fresh start)$/i;
if (resetPatterns.test(chatInput.trim())) {
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://n8n.realtysoft.ai/webhook/property-search',
      body: {
        CLIENT_ID: CLIENT_ID,
        session_id: sessionId,
        location_name: '',
        property_type: '',
        list_price_min: 0,
        list_price_max: 0,
        bedrooms_min: 0,
        bedrooms_max: 0,
        bathrooms_min: 0,
        bathrooms_max: 0,
        features: '',
        clear_all_filters: true
      },
      headers: { 'Content-Type': 'application/json' },
      json: true
    });
  } catch (e) {}
  return '✅ All filters have been cleared! You can now start a fresh search.\n\nWhat type of property are you looking for? For example: "villas in marbella" or "3 bed apartments in estepona"';
}

// Check for reference number
const refNo = parseRefNo(chatInput);
if (refNo) {
  try {
    const response = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://n8n.realtysoft.ai/webhook/property-search',
      body: { CLIENT_ID: CLIENT_ID, session_id: sessionId, ref_no: refNo, PROP_DETAIL_URL: PROP_DETAIL_URL },
      headers: { 'Content-Type': 'application/json' },
      json: true
    });
    if (response && response.result) return response.result;
    return `No property found with reference ${refNo}.`;
  } catch (error) {
    return 'I encountered an issue searching for that property. Please try again.';
  }
}

// Standard search - parse all parameters
const typeResult = findPropertyType(chatInput, TYPE_MAP);
const priceResult = parsePrice(chatInput);
const bedrooms = parseBedrooms(chatInput);
const bathrooms = parseBathrooms(chatInput);

// Find locations (check for multiple)
const multiLocations = findMultipleLocations(chatInput, LOCATION_MAP);
const singleLocation = findLocation(chatInput, LOCATION_MAP);

// Build request body with multi-location support
// When multiple locations found -> use location_ids array and search_mode: 'multi'
// When single location found -> use location_id and search_mode: 'single'
const requestBody = {
  CLIENT_ID: CLIENT_ID,
  session_id: sessionId,

  // Multi-location support
  // When multiple locations: use location_ids array and set location_id to null
  // When single location: use location_id
  location_id: multiLocations.length > 1 ? null : (multiLocations.length === 1 ? multiLocations[0].id : (singleLocation ? singleLocation.id : null)),
  location_name: multiLocations.length > 1 ? '' : (multiLocations.length === 1 ? multiLocations[0].name : (singleLocation ? singleLocation.match : '')),
  location_ids: multiLocations.length > 1 ? multiLocations.map(l => l.id) : [],
  location_names: multiLocations.length > 1 ? multiLocations.map(l => l.name) : [],
  search_mode: multiLocations.length > 1 ? 'multi' : 'single',

  // Property type (now uses longest match)
  property_type: typeResult ? typeResult.match : '',
  type_id: typeResult ? typeResult.id : null,

  // Price filters
  list_price_min: priceResult.price_min || 0,
  list_price_max: priceResult.price_max || 0,

  // Bedroom/bathroom filters
  bedrooms_min: bedrooms.min || 0,
  bedrooms_max: bedrooms.max || 0,
  bathrooms_min: bathrooms.min || 0,
  bathrooms_max: bathrooms.max || 0,

  // Additional context
  pre_parsed: (multiLocations.length > 0 || singleLocation) && typeResult ? true : false,
  PROP_DETAIL_URL: PROP_DETAIL_URL
};

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://n8n.realtysoft.ai/webhook/property-search',
    body: requestBody,
    headers: { 'Content-Type': 'application/json' },
    json: true
  });

  if (response && response.result) return response.result;
  if (response && response.formatted_response) return response.formatted_response;
  if (typeof response === 'string') return response;
  return JSON.stringify(response);
} catch (error) {
  return 'I encountered an issue searching for properties. Please try again.';
}

const inputData = $input.first().json;
const agentResponse = inputData.output || inputData.text || inputData.response || inputData.content || inputData.message || '';
const sessionId = inputData.sessionId || inputData.session_id || '';
const clientId = inputData.client_id || inputData.CLIENT_ID || '';

const userData = {
  name: inputData.name || '',
  email: inputData.email || '',
  phone: inputData.phone || ''
};

let result = {
  event_detected: false,
  event_type: 'none',
  session_id: sessionId,
  client_id: clientId,
  clean_response: agentResponse,
  user_data: userData
};

// Check for STORE_USER_DATA marker
const storeDataPattern = /STORE_USER_DATA:\s*name=\[(.*?)\],\s*email=\[(.*?)\],\s*phone=\[(.*?)\]/i;
const storeDataMatch = agentResponse.match(storeDataPattern);

if (storeDataMatch) {
  result.event_detected = true;
  result.event_type = 'store_contact';
  result.user_data = {
    full_name: storeDataMatch[1].trim() || null,
    email: storeDataMatch[2].trim() || null,
    phone: storeDataMatch[3].trim() || null,
    session_id: sessionId,
    client_id: clientId
  };
  result.clean_response = agentResponse.replace(storeDataPattern, '').trim();
}

// Check for CHAT_END_CONFIRMED marker
if (agentResponse && agentResponse.includes('CHAT_END_CONFIRMED')) {
  result.event_detected = true;
  result.event_type = 'chat_end';
  result.clean_response = agentResponse.replace(/CHAT_END_CONFIRMED/g, '').trim();
}

// Safety: ensure we always have something in clean_response
if (!result.clean_response || result.clean_response.trim() === '') {
  result.clean_response = agentResponse || "I'm here to help!";
}

return result;

// Prepare endChat request for Route by Event
const ctx = $('Prepare Client Context').first().json;
const data = $input.first().json;

return {
  json: {
    event_type: 'chat_end',
    event_detected: true,
    session_id: data.sessionId || ctx.sessionId,
    client_id: data.CLIENT_ID || ctx.CLIENT_ID,
    clean_response: 'Chat transcript sent!',
    user_data: {
      name: data.name || '',
      email: data.email || '',
      phone: data.phone || ''
    }
  }
};
